import React, { useEffect, useState } from 'react';
import './ProductionOutput.css';

const ProductionOutput = () => {
    const [products, setProducts] = useState([]);
    const [staff, setStaff] = useState([]);
    const [selectedProduct, setSelectedProduct] = useState('');
    const [goodProducts, setGoodProducts] = useState(0);
    const [damagedProducts, setDamagedProducts] = useState(0);
    const [efficiency, setEfficiency] = useState(0);
    const [participatingStaff, setParticipatingStaff] = useState([]);

    useEffect(() => {
        const fetchProductsAndStaff = async () => {
            try {
                const productResponse = await fetch('http://localhost:8000/api/v1/products');
                const staffResponse = await fetch('http://localhost:8000/api/v1/staff');

                if (!productResponse.ok || !staffResponse.ok) {
                    throw new Error('Failed to fetch data');
                }

                setProducts(await productResponse.json());
                setStaff(await staffResponse.json());
            } catch (error) {
                console.error('Error fetching data:', error);
            }
        };

        fetchProductsAndStaff();
    }, []);

    const calculateEfficiency = () => {
        const totalProducts = goodProducts + damagedProducts;
        if (totalProducts > 0) {
            setEfficiency(((goodProducts / totalProducts) * 100).toFixed(2));
        } else {
            setEfficiency(0);
        }
    };

    const handleSubmit = async (e) => {
        e.preventDefault();
        try {
            const response = await fetch('http://localhost:8000/api/v1/production-output', {
                method: 'POST',
                headers: {
                    'Content-Type': 'application/json'
                },
                body: JSON.stringify({
                    productId: selectedProduct,
                    goodProducts,
                    damagedProducts,
                    efficiency,
                    participatingStaff
                })
            });

            if (!response.ok) {
                throw new Error('Failed to submit production output');
            }

            alert('Production output recorded successfully!');
        } catch (error) {
            console.error('Error submitting production output:', error);
            alert('Failed to record production output. Please try again.');
        }
    };

    return (
        <div className="production-output-container">
            <h1>Production Output</h1>
            <form onSubmit={handleSubmit}>
                <label>
                    Product:
                    <select value={selectedProduct} onChange={(e) => setSelectedProduct(e.target.value)} required>
                        <option value="">Select a product</option>
                        {products.map((product) => (
                            <option key={product.id} value={product.id}>{product.name}</option>
                        ))}
                    </select>
                </label>
                <label>
                    Good Products:
                    <input
                        type="number"
                        value={goodProducts}
                        onChange={(e) => setGoodProducts(e.target.value)}
                        onBlur={calculateEfficiency}
                        required
                    />
                </label>
                <label>
                    Damaged Products:
                    <input
                        type="number"
                        value={damagedProducts}
                        onChange={(e) => setDamagedProducts(e.target.value)}
                        onBlur={calculateEfficiency}
                        required
                    />
                </label>
                <label>
                    Efficiency: {efficiency}%
                </label>
                <label>
                    Participating Staff:
                    <select
                        multiple
                        value={participatingStaff}
                        onChange={(e) => setParticipatingStaff([...e.target.selectedOptions].map(option => option.value))}
                    >
                        {staff.map((member) => (
                            <option key={member.id} value={member.id}>{member.name}</option>
                        ))}
                    </select>
                </label>
                <button type="submit">Submit</button>
            </form>
        </div>
    );
};

export default ProductionOutput;
